async (page) => {
  // Set attack style to Hack for Strength XP
  await page.evaluate(() => {
    window.game.player.setAttackStyle(1); // 1 = Hack (Strength)
  });
  await page.waitForTimeout(500);

  // Warp to Mudwich
  await page.evaluate(() => {
    window.game.menu.warp.show();
    setTimeout(() => document.getElementById('warp0').click(), 500);
  });
  await page.waitForTimeout(3000);
  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return 'Set Hack style and warped to Mudwich';
}

async (page) => {
  // Click the Rat visible near my character (to the left)
  await page.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: 512, y: 360 });
  await page.waitForTimeout(5000);
  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    if (!s) return null;
    return {
      player_position: s.player_position,
      player_stats: s.player_stats,
      nearest_mob: s.nearest_mob,
      current_target: s.current_target,
      last_combat: s.last_combat,
      last_xp_event: s.last_xp_event
    };
  });
  return JSON.stringify(state);
}

