async (page) => {
  const strengthBefore = await page.evaluate(() => window.game.player.skills[6].experience);

  // Click Rat at click_x=448, same y as player = screen 375
  await page.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: 448, y: 375 });
  await page.waitForTimeout(8000);

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const player = window.game.player;
    return {
      player_position: s.player_position,
      current_target: s.current_target ? { name: s.current_target.name, hp: s.current_target.hp } : null,
      strength_xp: player.skills[6].experience,
      defense_xp: player.skills[7].experience,
      strength_level: player.skills[6].level
    };
  });
  state.strength_xp_gained = state.strength_xp - strengthBefore;
  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return JSON.stringify(state);
}

